static const uint8_t manchester_lut[16] = {
    0x55, 0x56, 0x59, 0x5A, 0x65, 0x66, 0x69, 0x6A,
    0x95, 0x96, 0x99, 0x9A, 0xA5, 0xA6, 0xA9, 0xAA
};

void hal_transmit(const uint8_t* erp1_data, size_t len) {
    if (!erp1_data || len == 0) return;

    xSemaphoreTake(spi_mutex, portMAX_DELAY);

    // 1. Switch to TX mode (Packet mode)
    cc1101_strobe(0x36); // SIDLE
    cc1101_write_reg(0x02, 0x06); // GDO2: Sync/End of Packet
    cc1101_write_reg(0x12, 0x30); // MDMCFG2: OOK, No Sync
    cc1101_write_reg(0x08, 0x00); // PKTCTRL0: Fixed length

    // 2. Prepare FIFO
    uint8_t tx_buf[64];
    size_t tx_idx = 0;

    // 8 Bytes Preamble/SOF: 31 logische 1er + 1 logische 0 (SOF)
    for(int i=0; i<7; i++) tx_buf[tx_idx++] = 0xAA;
    tx_buf[tx_idx++] = 0xA9; // '1110' -> 10 10 10 01

    // Payload Manchester-kodieren
    for (size_t i = 0; i < len && tx_idx < 62; i++) {
        uint8_t byte = erp1_data[i];
        tx_buf[tx_idx++] = manchester_lut[byte >> 4];
        tx_buf[tx_idx++] = manchester_lut[byte & 0x0F];
    }
    tx_buf[tx_idx++] = 0x00; // Post-amble (OOK off)

    cc1101_write_reg(0x06, tx_idx); // PKTLEN
    cc1101_strobe(0x3B); // SFTX
    cc1101_write_burst(0x3F, tx_buf, tx_idx); // FIFO Write
    cc1101_strobe(0x35); // STX

    // Warte bis Senden abgeschlossen (GDO2 fällt ab)
    // Da wir in einem Task laufen, ist ein kurzes Polling hier akzeptabel
    int timeout = 1000;
    while(gpio_get_level(GPIO_NUM_3) && --timeout > 0) {
        ets_delay_us(10);
    }

    // 3. Switch back to RX (Async)
    cc1101_strobe(0x36); // SIDLE
    cc1101_write_reg(0x02, 0x0D); // GDO2: Async Serial Out
    cc1101_write_reg(0x08, 0x02); // PKTCTRL0: Async
    cc1101_strobe(0x34); // SRX

    xSemaphoreGive(spi_mutex);
}

