def calc_crc8(data):
    crc = 0
    for byte in data:
        crc = CRC8_TABLE[crc ^ byte]
    return crc

def build_esp3_packet(packet_type, data, opt_data=b''):
    # Header: Data Length (2 Byte), Opt. Data Length (1 Byte), Type (1 Byte)
    header = struct.pack(">HBB", len(data), len(opt_data), packet_type)
    crc8h = calc_crc8(header)

    payload = data + opt_data
    crc8d = calc_crc8(payload)

    # Sync-Byte (0x55) + Header + CRC8H + Payload + CRC8D
    return b'\x55' + header + bytes([crc8h]) + payload + bytes([crc8d])

def create_pulse_string(pulses):
    """
    Konvertiert eine Liste aus (Level, Duration) Tuples in unseren Hex-String.
    Level: 1 oder 0, Duration: microseconds
