    hex_str = ""
    for level, duration in pulses:
        # Dauer auf 15 bit kappen
        duration = duration & 0x7FFF
        # Level in Bit 15 setzen
        val = duration | (0x8000 if level else 0)
        hex_str += f"{val:04X}"
    return hex_str

