            print(f"Empfangen (Hex): {response.hex().upper()}")
            if response[0] == 0x55 and response[4] == 0x01: # Sync und Type ERP1
                print("ERFOLG: Der Decoder hat das virtuelle Signal erkannt und ein ESP3 ERP1 Paket generiert!")
        else:
            print("FEHLER: Keine Antwort. State-Machine hat die Pulse verworfen (Timing falsch?) oder RX-Logik fehlerhaft.")

except Exception as e:
